import Tesseract from 'tesseract.js';
import { jsPDF } from "jspdf";
import React, { useState, useEffect } from 'react';
import CrmLogoFull from './assets/logo.png';
import { supabase } from './supabaseClient';
import { 
  User, LogOut, Heart, Activity, Zap, Menu, X, 
  UserCircle, Clipboard, Save, Info, ChevronDown, ChevronRight,
  Plus, History, Folder, Moon, BookOpen, Bell, Lightbulb 
} from 'lucide-react';
import './Dashboard.css';

const HeartAnimation = "https://cdn-icons-png.flaticon.com/512/833/833472.png"; 
const KidneyAnimation = "https://cdn-icons-png.flaticon.com/512/2906/2906231.png";

const Dashboard = ({ user, onLogout }) => {
  // --- 1. STATE MANAGEMENT ---
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isAnalysing, setIsAnalysing] = useState(false);
  const [showClinicalModal, setShowClinicalModal] = useState(false);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [selectedFiles, setSelectedFiles] = useState([]);
  const [mobileMenu, setMobileMenu] = useState(false);
  const [subMenus, setSubMenus] = useState({ health: false, reports: false });
  const [pastReports, setPastReports] = useState([]);
  const [selectedReport, setSelectedReport] = useState(null);

  const [formData, setFormData] = useState({
    age: '', weight: '', height: '', full_name: '',
    bp_sys: '', bp_dia: '', sugar: '', creatine: '',
    phone: '', address: '', gender: '',
    smoking: 'No', alcohol: 'No', activity: 'Sedentary',
    sleep: '', comorbidities: ''
  });

  // --- 2. DATA FETCHING ---
  const fetchReports = async () => {
    if (!user) return;
    try {
      const { data, error } = await supabase
        .from('reports')
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false });
      if (error) throw error;
      setPastReports(data || []);
    } catch (err) { console.error("Vault Error:", err.message); }
  };

  const getProfile = async () => {
    if (!user) return;
    try {
      let { data, error } = await supabase.from('profiles').select('*').eq('id', user.id).single();
      if (data) {
        setProfile(data);
        setFormData(prev => ({ ...prev, ...data }));
      }
    } catch (err) { console.error("Profile Load Error:", err); } 
    finally { setLoading(false); }
  };

  useEffect(() => {
    if (user) { getProfile(); fetchReports(); }
  }, [user]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const toggleSubMenu = (menu) => setSubMenus(prev => ({ ...prev, [menu]: !prev[menu] }));

  // --- 3. THE REPAIRED ANALYSIS ENGINE (Pathology + Dual Reports) ---
  const runAnalysisAndDownload = async () => {
    setIsAnalysing(true);
    let finalData = { ...formData };
    
    try {
      // PHASE A: AI OCR
      if (selectedFiles.length > 0) {
        const imageUrl = URL.createObjectURL(selectedFiles[0]);
        const { data: { text } } = await Tesseract.recognize(imageUrl, 'eng');
        URL.revokeObjectURL(imageUrl);
        const sugarMatch = text.match(/(?:glucose|sugar|glu)\D+(\d{2,3})/i);
        const creatineMatch = text.match(/(?:creatinine|crea)\D+(\d?\.?\d)/i);
        if (sugarMatch) finalData.sugar = sugarMatch[1];
        if (creatineMatch) finalData.creatine = creatineMatch[1];
      }

      // PHASE B: PROFILE SYNC
      const sanitizedData = {
        id: user.id, ...finalData,
        age: parseInt(finalData.age) || 0,
        bp_sys: parseInt(finalData.bp_sys) || 0,
        sugar: parseInt(finalData.sugar) || 0,
        creatine: parseFloat(finalData.creatine) || 0.0
      };
      const { data: updatedProfile } = await supabase.from('profiles').upsert(sanitizedData).select().single();
      setProfile(updatedProfile);

      // PHASE C: INITIALIZE PATHOLOGY LOGIC
      const heartRisk = sanitizedData.bp_sys > 140 || sanitizedData.smoking === 'Yes' ? "High Risk" : "Stable";
      const kidneyRisk = sanitizedData.creatine > 1.2 ? "Elevated Stress" : "Optimal";
      const sugarRisk = sanitizedData.sugar > 140 ? "Imbalanced" : "Stable";

      const heartExp = heartRisk === "High Risk" ? "High pressure causing arterial wall thickening (Hypertrophy)." : "Vascular elasticity is maintained.";
      const kidneyExp = kidneyRisk === "Elevated Stress" ? "Reduced filtration rate leads toward Chronic Kidney Disease (CKD)." : "Nephron filtration is performing at peak capacity.";
      const sugarExp = sugarRisk === "Imbalanced" ? "Hyperglycemia damaging microvessels and nerves." : "Glucose transport is efficiently managed.";

      // PHASE D: REPORT 1 (FULL CLINICAL)
      const doc1 = new jsPDF();
      doc1.setFillColor(15, 23, 42); doc1.rect(0, 0, 210, 45, 'F');
      doc1.setTextColor(255, 255, 255); doc1.setFontSize(18); doc1.text("FULL CLINICAL DIAGNOSTIC", 20, 25);
      doc1.setTextColor(30, 41, 59); doc1.text(`Cardiac: ${heartExp}`, 20, 60);
      doc1.save(`CRM_Full_Clinical_${Date.now()}.pdf`);

      // PHASE E: REPORT 2 (QUICK SNAPSHOT)
      const doc2 = new jsPDF();
      doc2.text("SYSTEMIC QUICK SNAPSHOT", 20, 20);
      doc2.save(`CRM_Quick_Snapshot_${Date.now()}.pdf`);

      // PHASE F: VAULT SYNC
      const { data: savedReport } = await supabase.from('reports').insert([{
        user_id: user.id, report_name: `Analysis_${new Date().toLocaleDateString()}`,
        report_data: finalData, risk_score: heartRisk === "High Risk" ? 75 : 10
      }]).select();
      if (savedReport) setPastReports(prev => [savedReport[0], ...prev]);

      setShowClinicalModal(false);
      alert("Analysis Complete & Saved to Vault!");
    } catch (err) { alert(err.message); } finally { setIsAnalysing(false); }
  };

  if (loading) return <div className="status-screen">Initializing CRM...</div>;
  const bmi = profile?.height ? (profile.weight / (profile.height / 100) ** 2).toFixed(1) : '--';

  return (
    <div className="dashboard-container">
      <header className="dash-header">
        <div className="dash-nav-logo">
          <span className="logo-text">CRM Analysis</span>
          <img src={CrmLogoFull} alt="Logo" className="header-logo" />
        </div>
        <div className="nav-controls">
          <span className="user-welcome">Welcome, {profile?.full_name || 'Patient'}</span>
          <button className="mobile-menu-btn" onClick={() => setMobileMenu(!mobileMenu)}><Menu /></button>
        </div>
      </header>

      <div className="dash-main-wrapper">
        <aside className={`dash-sidebar ${mobileMenu ? 'active' : ''}`}>
          <div className="sidebar-header">
            <UserCircle size={50} color="#6366f1" />
            <h2 className="user-name">{profile?.full_name || "Patient"}</h2>
          </div>
          <nav className="sidebar-nav">
            <button className="nav-item active"><Activity size={18} /> Dashboard</button>
            <button className="nav-item-btn" onClick={() => toggleSubMenu('health')}>
              <Heart size={18} /> Health {subMenus.health ? <ChevronDown size={14}/> : <ChevronRight size={14}/>}
            </button>
            {subMenus.health && (
              <div className="sub-menu">
                <button onClick={() => setShowClinicalModal(true)}><Plus size={12}/> Clinical Center</button>
              </div>
            )}
            <button className="nav-item-btn" onClick={() => toggleSubMenu('reports')}>
              <Folder size={18} /> Health Vault {subMenus.reports ? <ChevronDown size={14}/> : <ChevronRight size={14}/>}
            </button>
            {subMenus.reports && (
              <div className="sub-menu">
                {pastReports.map(r => <button key={r.id} onClick={() => setSelectedReport(r)}><BookOpen size={12}/> {r.report_name}</button>)}
              </div>
            )}
            <button className="nav-item-btn" onClick={() => setShowProfileModal(true)}><Clipboard size={18} /> Profile</button>
            <button onClick={onLogout} className="nav-item-btn" style={{color:'#ef4444'}}><LogOut size={18} /> Logout</button>
          </nav>
        </aside>

        <main className="dash-content-area">
          {profile && (
            <section className="user-profile-summary-card">
              <div className="profile-main-info">
                <h3>{profile.full_name}</h3>
                <p>ID: {user.id.slice(0,8)} | {profile.age} Yrs | {profile.gender}</p>
              </div>
              <div className="profile-tags">
                <span className="p-tag">BP: {profile.bp_sys}/{profile.bp_dia}</span>
                <span className="p-tag">Sugar: {profile.sugar}</span>
                <span className="p-tag lifestyle">Activity: {profile.activity}</span>
              </div>
            </section>
          )}

          <div className="crm-grid">
            <div className={`crm-status-box ${profile?.bp_sys > 140 ? 'status-critical' : ''}`}>
              <img src={HeartAnimation} className="crm-animated-icon" />
              <div className="crm-info"><h4>Cardiac</h4><div className="crm-reading">{profile?.bp_sys || '--'}</div></div>
            </div>
            <div className={`crm-status-box ${profile?.creatine > 1.2 ? 'status-critical' : ''}`}>
              <img src={KidneyAnimation} className="crm-animated-icon" />
              <div className="crm-info"><h4>Renal</h4><div className="crm-reading">{profile?.creatine || '--'}</div></div>
            </div>
            <div className={`crm-status-box ${profile?.sugar > 140 ? 'status-critical' : ''}`}>
              <Zap color="#f59e0b" size={32} />
              <div className="crm-info"><h4>Metabolic</h4><div className="crm-reading">{profile?.sugar || '--'}</div></div>
            </div>
          </div>

          <div className="pathology-forecast-section">
            <h3 className="sub-section-title"><Bell size={16} /> Critical Pathological Forecast</h3>
            <div className="pathology-grid">
              <div className={`path-card ${profile?.bp_sys > 140 ? 'danger-zone' : ''}`}>
                <h4>Neuro-Cardiac Pathway</h4>
                <p>{profile?.bp_sys > 140 ? "Warning: Foundation for Stroke or Heart Attack detected." : "Vascular tension is stable."}</p>
              </div>
              <div className={`path-card ${profile?.creatine > 1.3 ? 'danger-zone' : ''}`}>
                <h4>Renal Pathway</h4>
                <p>{profile?.creatine > 1.3 ? "Warning: Progression toward Dialysis detected." : "Filtration capacity is healthy."}</p>
              </div>
            </div>
          </div>
        </main>
      </div>

      {/* MODALS (Clinical / Profile) */}
      {showClinicalModal && (
        <div className="modal-overlay">
          <div className="profile-modal-container">
            <div className="modal-header-fixed"><h2>Clinical Center</h2><button onClick={()=>setShowClinicalModal(false)}><X/></button></div>
            <div className="unified-grid profile-expanded-grid">
               <div className="field-group"><label>BP Systolic</label><input type="number" name="bp_sys" value={formData.bp_sys} onChange={handleInputChange} /></div>
               <div className="field-group"><label>Sugar</label><input type="number" name="sugar" value={formData.sugar} onChange={handleInputChange} /></div>
               <div className="field-group"><label>Creatine</label><input type="number" step="0.1" name="creatine" value={formData.creatine} onChange={handleInputChange} /></div>
               <div className="compact-upload-zone" onClick={() => document.getElementById('f-up').click()}>
                  <Folder size={32} />
                  <input type="file" id="f-up" hidden onChange={(e)=>setSelectedFiles([e.target.files[0]])} />
                  <p>Upload Lab Report</p>
               </div>
            </div>
            <div style={{padding:'20px'}}><button className="btn-primary-save" style={{width:'100%'}} onClick={runAnalysisAndDownload} disabled={isAnalysing}>{isAnalysing ? "Analyzing..." : "Run Analysis"}</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
